// index.js
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// Hardcoded API keys for development environment
// IMPORTANT: Replace with Azure Key Vault references for production!
const SENDGRID_API_KEY = 'SG.azure_demo_key_123';
const TWILIO_ACCOUNT_SID = 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = 'your_twilio_auth_token_here'; // You'll need to generate or obtain this from Twilio

// Initialize SendGrid
sgMail.setApiKey(SENDGRID_API_KEY);

// Initialize Twilio
const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

module.exports = async function (context, req) {
    context.log('Azure Function triggered for SendGrid and Twilio integration.');

    const {
        emailTo,
        emailSubject,
        emailText,
        smsTo,
        smsBody,
        sendFromEmail = 'noreply@yourdomain.com', // Default sender email
        sendFromSms = '+15017122661' // Your Twilio phone number (must be purchased from Twilio)
    } = req.body || {};

    let emailSent = false;
    let smsSent = false;
    const errors = [];
    const messages = [];

    // Send Email via SendGrid
    if (emailTo && emailSubject && emailText) {
        const msg = {
            to: emailTo,
            from: sendFromEmail,
            subject: emailSubject,
            text: emailText,
            html: `<strong>${emailText}</strong>`, // Optional: provide HTML version
        };

        try {
            await sgMail.send(msg);
            emailSent = true;
            messages.push(`Email sent to ${emailTo}`);
            context.log(`Email sent to ${emailTo}`);
        } catch (error) {
            emailSent = false;
            errors.push(`Failed to send email: ${error.message}`);
            context.error(`Failed to send email: ${error.message}`, error);
            if (error.response) {
                context.error(error.response.body);
            }
        }
    } else if (req.body && (emailTo || emailSubject || emailText)) {
        errors.push("Missing required fields for email: 'emailTo', 'emailSubject', and 'emailText' are all required if sending email.");
    }

    // Send SMS via Twilio
    if (smsTo && smsBody && sendFromSms) {
        try {
            await twilioClient.messages.create({
                body: smsBody,
                to: smsTo,
                from: sendFromSms
            });
            smsSent = true;
            messages.push(`SMS sent to ${smsTo}`);
            context.log(`SMS sent to ${smsTo}`);
        } catch (error) {
            smsSent = false;
            errors.push(`Failed to send SMS: ${error.message}`);
            context.error(`Failed to send SMS: ${error.message}`, error);
        }
    } else if (req.body && (smsTo || smsBody)) {
        errors.push("Missing required fields for SMS: 'smsTo', 'smsBody', and 'sendFromSms' are all required if sending SMS.");
    }


    if (errors.length > 0) {
        context.res = {
            status: 500,
            body: {
                success: false,
                emailSent: emailSent,
                smsSent: smsSent,
                messages: messages,
                errors: errors
            }
        };
    } else if (emailSent || smsSent) {
        context.res = {
            status: 200,
            body: {
                success: true,
                emailSent: emailSent,
                smsSent: smsSent,
                messages: messages
            }
        };
    } else {
        context.res = {
            status: 400,
            body: {
                success: false,
                message: "No valid email or SMS parameters provided in the request body.",
                example_body: {
                    emailTo: "test@example.com",
                    emailSubject: "Hello from Azure Function",
                    emailText: "This is a test email sent via SendGrid.",
                    smsTo: "+1234567890",
                    smsBody: "This is a test SMS from Azure Function via Twilio.",
                    sendFromEmail: "noreply@yourdomain.com",
                    sendFromSms: "+15017122661"
                }
            }
        };
    }
};